INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fadf8d19-78d6-4d5a-ac2b-9deb10e05f79',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum Security — CORS, Rate Limiting, and Hardened Headers in One Stack$escape$,
  $escape$axum's `Tower` middleware ecosystem handles most security concerns without reaching for external crates beyond `tower-http`. For CORS, `CorsLayer::new()` gives you per-route origin/method/header control — never use `CorsLayer::permissive()` in production. Security headers come from `SetResponseHeaderLayer` or, more ergonomically, `tower_http::set_header::SetResponseHeaderLayer` combined with `SecureHeaders` from `tower-http`'s `sensitive_headers` module to strip auth tokens from traces.

For rate limiting, `tower::limit::ConcurrencyLimitLayer` caps concurrent connections, but IP-based throttling needs `tower_governor` with an `axum::extract::ConnectInfo<SocketAddr>` extractor feeding a `GovernorLayer`. Injection prevention in axum is primarily about never interpolating `Path`/`Query` extractor values directly into raw SQL — always use `sqlx::query!` macros with bound parameters. Validate all deserialized `Json<T>` payloads with `validator` crate attributes on your request structs so malformed input is rejected at the extractor layer before reaching your handlers.$escape$,
  $escape$use tower_http::cors::{CorsLayer, Any};
use tower_governor::{governor::GovernorConfigBuilder, GovernorLayer};
use std::sync::Arc;

let governor_conf = Arc::new(
    GovernorConfigBuilder::default()
        .per_second(10)
        .burst_size(20)
        .finish()
        .unwrap(),
);

let app = Router::new()
    .route("/api/data", get(handler))
    .layer(GovernorLayer { config: governor_conf })
    .layer(
        CorsLayer::new()
            .allow_origin("https://yourdomain.com".parse::<HeaderValue>().unwrap())
            .allow_methods([Method::GET, Method::POST]),
    );$escape$,
  $escape$rust$escape$,
