INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1a8e735e-93b1-40ae-9ee6-1e76727fa98b',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum Performance — Connection Pooling, Async Handlers, and Response Compression$escape$,
  $escape$axum's async handlers run on Tokio, so blocking inside them stalls the runtime. Always use `tokio::task::spawn_blocking` for CPU-bound work and never call synchronous database drivers directly. Pair axum with `sqlx::PgPool` — create one pool at startup, store it in `axum::Extension` or application state via `axum::extract::State`, and pass it into handlers. Pool size should match `max_connections` on your Postgres instance; a common starting point is `PgPoolOptions::new().max_connections(20)`. For response compression, add `tower_http::compression::CompressionLayer` to your router — it negotiates `gzip`, `br`, and `deflate` via the `Accept-Encoding` header automatically. Stack it after `TraceLayer` so compressed bytes don't pollute trace spans. Avoid compressing small responses (under ~1 KB) since compression overhead outweighs savings; `CompressionLayer` lets you set a `minimum_size` threshold. Together, these three changes — pooled DB connections, non-blocking async handlers, and selective compression — address the most common throughput bottlenecks in a production axum service without reaching for a reverse proxy.$escape$,
  $escape$use axum::{extract::State, routing::get, Router};
use sqlx::PgPool;
use tower_http::compression::CompressionLayer;

#[tokio::main]
async fn main() {
    let pool = sqlx::postgres::PgPoolOptions::new()
        .max_connections(20)
        .connect("postgres://localhost/mydb").await.unwrap();

    let app = Router::new()
        .route("/users", get(list_users))
        .layer(CompressionLayer::new().quality(tower_http::CompressionLevel::Fastest))
        .with_state(pool);

    axum::serve(tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap(), app)
        .await.unwrap();
}

async fn list_users(State(pool): State<PgPool>) -> String {
    let count: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM users")
        .fetch_one(&pool).await.unwrap();
    format!("{{\"count\": {}}}", count.0)
}$escape$,
  $escape$rust$escape$,
