INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eef4a5e8-1177-4b10-b3c8-0b4176f9a151',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum's Custom Extractors — Your Framework-Level Batteries$escape$,
  $escape$Unlike Django's batteries-included auth or NestJS decorators, axum ships lean — but its `FromRequestParts` trait lets you bolt on the same ergonomics yourself, with full type safety baked in at the handler signature level.

Implement `FromRequestParts` on any struct and axum will automatically call it before invoking your handler. This means JWT validation, tenant resolution, feature flags, or rate-limit context can all live as zero-boilerplate extractor arguments — no middleware plumbing into `Extension`, no manual `req.extensions().get::<T>()` unwrapping.

The key distinction from other frameworks: rejection is typed. Your extractor returns `Result<Self, Self::Rejection>`, where `Rejection` implements `IntoResponse`. A failed auth check short-circuits the handler and returns your exact error shape — no exception handlers or global error middleware needed.

Compose extractors freely: `ValidatedJson<T>` can wrap `Json<T>` internally, adding Serde deserialization *and* `validator` crate checks in one shot. Stack `AuthUser` + `ValidatedJson<CreatePostRequest>` in a single handler signature and axum resolves both in order, failing fast on the first rejection.$escape$,
  $escape$use axum::{async_trait, extract::{FromRequestParts, State}, http::{request::Parts, StatusCode}};

struct AuthUser(uuid::Uuid);

#[async_trait]
impl<S: Send + Sync> FromRequestParts<S> for AuthUser {
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let token = parts.headers
            .get("Authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.strip_prefix("Bearer "))
            .ok_or((StatusCode::UNAUTHORIZED, "missing token"))?;

        validate_jwt(token)
            .map(AuthUser)
            .map_err(|_| (StatusCode::UNAUTHORIZED, "invalid token"))
    }
}

async fn create_post(AuthUser(user_id): AuthUser, /* other extractors */) { }$escape$,
  $escape$rust$escape$,
